                            Enable Commission Permission Checks
                        </label>
                        <label style="display: block; margin: 5px 0;">
                            <input type="checkbox" id="enable-comm-html" 
                                {% if request.params.enableCommHtml != "false" %} checked {% endif %}>
                            Enable Commission HTML Generation
                        </label>
                    </div>
                    <div>
