                            Enable Adjustment Filtering Loop
                        </label>
                        <label style="display: block; margin: 5px 0;">
                            <input type="checkbox" id="enable-adj-permissions" 
                                {% if request.params.enableAdjPermissions != "false" %} checked {% endif %}>
                            Enable Adjustment Permission Checks
